class Solution:
    def longestSubstring(self, s: str, k: int) -> int:
        def solve(l, r):
            if r - l < k: return 0
            cnt = Counter(s[l:r])
            for i in range(l, r):
                if cnt[s[i]] < k:
                    return max(solve(l, i), solve(i+1, r))
            return r - l
        return solve(0, len(s))

