class Solution {
    int solve(string& s, int l, int r, int k) {
        if (r - l < k) return 0;
        int cnt[26] = {};
        for (int i = l; i < r; i++) cnt[s[i]-'a']++;
        for (int i = l; i < r; i++)
            if (cnt[s[i]-'a'] < k)
                return max(solve(s, l, i, k), solve(s, i+1, r, k));
        return r - l;
    }
public:
    int longestSubstring(string s, int k) {
        return solve(s, 0, s.size(), k);
    }
};

