static int solve(char* s, int l, int r, int k) {
    if (r-l < k) return 0;
    int cnt[26]={0};
    for (int i=l;i<r;i++) cnt[s[i]-'a']++;
    for (int i=l;i<r;i++) if (cnt[s[i]-'a']<k)
        return (solve(s,l,i,k) > solve(s,i+1,r,k) ? solve(s,l,i,k) : solve(s,i+1,r,k));
    return r-l;
}
int longestSubstring(char* s, int k) { return solve(s, 0, strlen(s), k); }
